				if (num == 2457 && WorldGen.crimson)
				{
					flag2 = true;
				}
				if (num == 2462 && !hardMode)
				{
					flag2 = true;
				}
				if (num == 2463 && (!hardMode || !WorldGen.crimson))
				{
					flag2 = true;
