				{
					flag2 = true;
				}
				if (num == 2468 && !hardMode)
				{
					flag2 = true;
				}
				if (num == 2471 && !hardMode)
				{
					flag2 = true;
				}
				if (num == 2473 && !hardMode)
				{
					flag2 = true;
				}
				if (num == 2477 && !WorldGen.crimson)
				{
					flag2 = true;
				}
				if (num == 2480 && !hardMode)
				{
					flag2 = true;
				}
				if (num == 2483 && !hardMode)
				{
					flag2 = true;
				}
				if (num == 2484 && !hardMode)
				{
					flag2 = true;
				}
				if (num == 2485 && WorldGen.crimson)
