			Configuration.Get("WaveQuality", ref WaveQuality);
			if (WaveQuality > 3)
			{
				WaveQuality = 3;
			}
			if (WaveQuality < 0)
			{
				WaveQuality = 0;
			}
			bool currentValue2 = false;
			int currentValue3 = graphics.PreferredBackBufferWidth;
			int currentValue4 = graphics.PreferredBackBufferHeight;
			Configuration.Get("Fullscreen", ref currentValue2);
			Configuration.Get("DisplayWidth", ref currentValue3);
			Configuration.Get("DisplayHeight", ref currentValue4);
			Dictionary<string, byte> currentValue5 = new Dictionary<string, byte>();
			Configuration.Get("MouseColor", ref currentValue5);
			if (currentValue5.TryGetValue("R", out var value))
			{
				mouseColor.R = value;
			}
			if (currentValue5.TryGetValue("G", out value))
			{
				mouseColor.G = value;
			}
			if (currentValue5.TryGetValue("B", out value))
			{
				mouseColor.B = value;
			}
			currentValue5.Clear();
			Configuration.Get("MouseBorderColor", ref currentValue5);
