					double num9 = stopwatch.Elapsed.TotalMilliseconds + num7;
					if (num9 < num6)
					{
						int num10 = (int)(num6 - num9) - 1;
						if (num10 > 1)
						{
							Thread.Sleep(num10 - 1);
							if (!Netplay.anyClients)
							{
								num7 = 0.0;
								Thread.Sleep(10);
							}
						}
					}
				}
				Thread.Sleep(0);
			}
