		public static void InitLifeBytes()
		{
			NPC nPC = new NPC();
			for (int i = -65; i < 580; i++)
			{
				if (i != 0)
				{
					nPC.SetDefaults(i);
					if (nPC.lifeMax > 32767 || nPC.boss)
					{
						npcLifeBytes[i] = 4;
					}
					else if (nPC.lifeMax > 127)
					{
						npcLifeBytes[i] = 2;
					}
					else
					{
						npcLifeBytes[i] = 1;
