		public static void stopMoonEvent()
		{
			if (pumpkinMoon)
			{
				pumpkinMoon = false;
				if (netMode != 1)
				{
					NPC.waveKills = 0f;
					NPC.waveNumber = 0;
				}
			}
			if (snowMoon)
			{
				snowMoon = false;
				if (netMode != 1)
				{
					NPC.waveKills = 0f;
					NPC.waveNumber = 0;
				}
			}
		}

		public static void startPumpkinMoon()
		{
			pumpkinMoon = true;
			snowMoon = false;
			bloodMoon = false;
			if (netMode != 1)
			{
				NPC.waveKills = 0f;
				NPC.waveNumber = 1;
				NetworkText invasionWaveText = Lang.GetInvasionWaveText(1, 305);
				if (netMode == 0)
				{
					NewText(invasionWaveText.ToString(), 175, 75);
				}
				else if (netMode == 2)
				{
					NetMessage.BroadcastChatMessage(invasionWaveText, new Microsoft.Xna.Framework.Color(175, 75, 255));
				}
			}
		}

		public static void startSnowMoon()
		{
			snowMoon = true;
			pumpkinMoon = false;
			bloodMoon = false;
			if (netMode != 1)
			{
				NPC.waveKills = 0f;
				NPC.waveNumber = 1;
				NetworkText invasionWaveText = Lang.GetInvasionWaveText(1, 338, 342);
				if (netMode == 0)
				{
					NewText(invasionWaveText.ToString(), 175, 75);
				}
				else if (netMode == 2)
				{
					NetMessage.BroadcastChatMessage(invasionWaveText, new Microsoft.Xna.Framework.Color(175, 75, 255));
				}
			}
		}

