				{
					foreach (ReLogic.Utilities.SlotVector<ActiveSound>.ItemPair item in (IEnumerable<ReLogic.Utilities.SlotVector<ActiveSound>.ItemPair>)_trackedSounds)
					{
						item.Value.Pause();
					}
				}
				else if (_areSoundsPaused && !flag)
				{
					foreach (ReLogic.Utilities.SlotVector<ActiveSound>.ItemPair item2 in (IEnumerable<ReLogic.Utilities.SlotVector<ActiveSound>.ItemPair>)_trackedSounds)
					{
						item2.Value.Resume();
					}
				}
				_areSoundsPaused = flag;
