				{
					foreach (ReLogic.Utilities.SlotVector<ActiveSound>.ItemPair item3 in (IEnumerable<ReLogic.Utilities.SlotVector<ActiveSound>.ItemPair>)_trackedSounds)
					{
						item3.Value.Update();
						if (!item3.Value.IsPlaying)
						{
							_trackedSounds.Remove(item3.Id);
