		private static void DoUpdate_HandleChat()
		{
			if (editSign)
			{
				drawingPlayerChat = false;
			}
			if (!drawingPlayerChat)
			{
				startChatLine = 0;
				return;
			}
			showCount = (int)((float)(screenHeight / 3) / fontMouseText.MeasureString("1").Y) - 1;
			if (keyState.IsKeyDown(Microsoft.Xna.Framework.Input.Keys.Up))
			{
				startChatLine++;
				if (startChatLine + showCount >= numChatLines - 1)
				{
					startChatLine = numChatLines - showCount - 1;
				}
				if (chatLine[startChatLine + showCount].text == "")
				{
					startChatLine--;
				}
			}
			else if (keyState.IsKeyDown(Microsoft.Xna.Framework.Input.Keys.Down))
			{
				startChatLine--;
				if (startChatLine < 0)
				{
					startChatLine = 0;
				}
			}
			if (keyState.IsKeyDown(Microsoft.Xna.Framework.Input.Keys.Escape))
			{
				drawingPlayerChat = false;
			}
			string text = chatText;
			chatText = GetInputText(chatText);
			int num = 470;
			num = (int)((float)screenWidth * (1f / UIScale)) - 330;
			if (text != chatText)
			{
				while (ChatManager.GetStringSize(fontMouseText, chatText, Vector2.One).X > (float)num)
				{
					chatText = chatText.Substring(0, chatText.Length - 1);
				}
			}
			if (text != chatText)
			{
				PlaySound(12);
			}
			if (!inputTextEnter || !chatRelease)
			{
				return;
			}
			if (chatText != "")
			{
				ChatMessage chatMessage = new ChatMessage(chatText);
				ChatManager.Commands.ProcessOutgoingMessage(chatMessage);
				NetMessage.SendChatMessageFromClient(chatMessage);
				if (netMode == 0)
				{
					Microsoft.Xna.Framework.Color c = player[myPlayer].ChatColor();
					_ = chatText;
					string text2 = NameTagHandler.GenerateTag(player[myPlayer].name) + " " + chatText;
					player[myPlayer].chatOverhead.NewMessage(chatText, chatLength / 2);
					NewTextMultiline(text2, force: false, c, TextMaxLengthForScreen);
				}
			}
			chatText = "";
			drawingPlayerChat = false;
			chatRelease = false;
			PlayerInput.WritingText = true;
			player[myPlayer].releaseHook = false;
			player[myPlayer].releaseThrow = false;
			PlaySound(11);
		}

