		private void DoUpdate_AnimateWaterfalls()
		{
			wFrCounter += windSpeed * 2f;
			if (wFrCounter > 4f)
			{
				wFrCounter = 0f;
				wFrame += 1f;
			}
			if (wFrCounter < 0f)
			{
				wFrCounter = 4f;
				wFrame -= 1f;
			}
			if (wFrame > 16f)
			{
				wFrame = 1f;
			}
			if (wFrame < 1f)
			{
				wFrame = 16f;
			}
			waterfallManager.UpdateFrame();
		}

		private static void DoUpdate_AnimateVisualPlayerAura()
		{
			if (gFadeDir == 1)
			{
				gFader += 0.1f;
				gFade = (byte)gFader;
				if (gFade > 150)
				{
					gFadeDir = 0;
				}
			}
			else
			{
				gFader -= 0.1f;
				gFade = (byte)gFader;
				if (gFade < 100)
				{
					gFadeDir = 1;
				}
			}
		}

		private void DoUpdate_AnimateDiscoRGB()
		{
			int num = 7;
			if (DiscoStyle == 0)
			{
				DiscoG += num;
				if (DiscoG >= 255)
				{
					DiscoG = 255;
					DiscoStyle++;
				}
			}
			if (DiscoStyle == 1)
			{
				DiscoR -= num;
				if (DiscoR <= 0)
				{
					DiscoR = 0;
					DiscoStyle++;
				}
			}
			if (DiscoStyle == 2)
			{
				DiscoB += num;
				if (DiscoB >= 255)
				{
					DiscoB = 255;
					DiscoStyle++;
				}
			}
			if (DiscoStyle == 3)
			{
				DiscoG -= num;
				if (DiscoG <= 0)
				{
					DiscoG = 0;
					DiscoStyle++;
				}
			}
			if (DiscoStyle == 4)
			{
				DiscoR += num;
				if (DiscoR >= 255)
				{
					DiscoR = 255;
					DiscoStyle++;
				}
			}
			if (DiscoStyle == 5)
			{
				DiscoB -= num;
				if (DiscoB <= 0)
				{
					DiscoB = 0;
					DiscoStyle = 0;
				}
			}
		}

		private static void DoUpdate_AnimateBackgrounds()
		{
			if (treeMntBG[1] == 94 || (treeMntBG[1] >= 114 && treeMntBG[1] <= 116))
			{
				bgFrameCounter[0]++;
				if (bgFrameCounter[0] >= 6)
				{
					bgFrameCounter[0] = 0;
					bgFrame[0]++;
					if (bgFrame[0] >= 4)
					{
						bgFrame[0] = 0;
					}
				}
				if (bgFrame[0] == 0)
				{
					treeMntBG[1] = 94;
				}
				else if (bgFrame[0] == 1)
				{
					treeMntBG[1] = 114;
				}
				else if (bgFrame[0] == 2)
				{
					treeMntBG[1] = 115;
				}
				else
				{
					treeMntBG[1] = 116;
				}
				if (bgFrame[0] == 0)
				{
					treeMntBG[0] = 93;
				}
				else if (bgFrame[0] == 1)
				{
					treeMntBG[0] = 168;
				}
				else if (bgFrame[0] == 2)
				{
					treeMntBG[0] = 169;
				}
				else
