			float num5 = 0f;
			float num6 = 0f;
			float num7 = 0f;
			float num8 = 255f;
			num -= 0.1f;
			if ((double)num > 0.5)
			{
				num6 = 255f;
				num5 = 255f * (1f - num) * 2f;
			}
			else
			{
				num6 = 255f * num * 2f;
				num5 = 255f;
			}
			float num9 = 0.95f;
			num5 = num5 * alpha * num9;
			num6 = num6 * alpha * num9;
			num8 = num8 * alpha * num9;
