					}
					if (projPet[projectile[j].type] && !projectile[j].minion && projectile[j].owner != 255 && projectile[j].damage == 0 && !ProjectileID.Sets.LightPet[projectile[j].type])
					{
						num4 = player[projectile[j].owner].cPet;
