		protected void DrawPlayers()
		{
			Vector2 position = default(Vector2);
			for (int i = 0; i < 255; i++)
			{
				Player player = Main.player[i];
				if (!player.active || player.outOfRange)
				{
					continue;
				}
				SamplerState samplerState = DefaultSamplerState;
				if (player.mount.Active)
				{
					samplerState = MountedSamplerState;
				}
				spriteBatch.Begin(SpriteSortMode.Immediate, BlendState.AlphaBlend, samplerState, DepthStencilState.None, Rasterizer, null, Transform);
				if (gamePaused)
				{
					player.PlayerFrame();
				}
				if (player.ghost)
				{
					for (int j = 0; j < 3; j++)
					{
						DrawGhost(player, player.shadowPos[j], 0.5f + 0.2f * (float)j);
					}
					DrawGhost(player, player.position);
					spriteBatch.End();
					continue;
				}
				if (player.inventory[player.selectedItem].flame || player.head == 137 || player.wings == 22)
				{
					player.itemFlameCount--;
					if (player.itemFlameCount <= 0)
					{
						player.itemFlameCount = 5;
						for (int k = 0; k < 7; k++)
						{
							player.itemFlamePos[k].X = (float)rand.Next(-10, 11) * 0.15f;
							player.itemFlamePos[k].Y = (float)rand.Next(-10, 1) * 0.35f;
						}
					}
				}
				if (player.armorEffectDrawShadowEOCShield)
				{
					int num = player.eocDash / 4;
					if (num > 3)
					{
						num = 3;
					}
					for (int l = 0; l < num; l++)
					{
						DrawPlayer(player, player.shadowPos[l], player.shadowRotation[l], player.shadowOrigin[l], 0.5f + 0.2f * (float)l);
					}
				}
				if (player.invis)
				{
					player.armorEffectDrawOutlines = false;
					player.armorEffectDrawShadow = false;
					player.armorEffectDrawShadowSubtle = false;
					position = player.position;
					if (player.aggro <= -750)
					{
						DrawPlayer(player, position, player.fullRotation, player.fullRotationOrigin, 1f);
					}
					else
					{
						player.invis = false;
						DrawPlayer(player, position, player.fullRotation, player.fullRotationOrigin);
						player.invis = true;
					}
				}
				if (player.armorEffectDrawOutlines)
				{
					_ = player.position;
					if (!gamePaused)
					{
						player.ghostFade += player.ghostDir * 0.075f;
					}
					if ((double)player.ghostFade < 0.1)
					{
						player.ghostDir = 1f;
						player.ghostFade = 0.1f;
					}
					else if ((double)player.ghostFade > 0.9)
					{
						player.ghostDir = -1f;
						player.ghostFade = 0.9f;
					}
					float num2 = player.ghostFade * 5f;
					for (int m = 0; m < 4; m++)
					{
						float num3;
						float num4;
						switch (m)
						{
						default:
							num3 = num2;
							num4 = 0f;
							break;
						case 1:
							num3 = 0f - num2;
							num4 = 0f;
							break;
						case 2:
							num3 = 0f;
							num4 = num2;
							break;
						case 3:
							num3 = 0f;
							num4 = 0f - num2;
							break;
						}
						position = new Vector2(player.position.X + num3, player.position.Y + player.gfxOffY + num4);
						DrawPlayer(player, position, player.fullRotation, player.fullRotationOrigin, player.ghostFade);
					}
				}
				if (player.armorEffectDrawOutlinesForbidden)
				{
					_ = player.position;
					if (!gamePaused)
					{
						player.ghostFade += player.ghostDir * 0.025f;
					}
					if ((double)player.ghostFade < 0.1)
					{
						player.ghostDir = 1f;
						player.ghostFade = 0.1f;
					}
					else if ((double)player.ghostFade > 0.9)
					{
						player.ghostDir = -1f;
						player.ghostFade = 0.9f;
					}
					float num5 = player.ghostFade * 5f;
					for (int n = 0; n < 4; n++)
					{
						float num6;
						float num7;
						switch (n)
						{
						default:
							num6 = num5;
							num7 = 0f;
							break;
						case 1:
							num6 = 0f - num5;
							num7 = 0f;
							break;
						case 2:
							num6 = 0f;
							num7 = num5;
							break;
						case 3:
							num6 = 0f;
							num7 = 0f - num5;
							break;
						}
						position = new Vector2(player.position.X + num6, player.position.Y + player.gfxOffY + num7);
						DrawPlayer(player, position, player.fullRotation, player.fullRotationOrigin, player.ghostFade);
					}
				}
				if (player.armorEffectDrawShadowBasilisk)
				{
					int num8 = (int)(player.basiliskCharge * 3f);
					for (int num9 = 0; num9 < num8; num9++)
					{
						DrawPlayer(player, player.shadowPos[num9], player.shadowRotation[num9], player.shadowOrigin[num9], 0.5f + 0.2f * (float)num9);
					}
				}
				else if (player.armorEffectDrawShadow)
				{
					for (int num10 = 0; num10 < 3; num10++)
					{
						DrawPlayer(player, player.shadowPos[num10], player.shadowRotation[num10], player.shadowOrigin[num10], 0.5f + 0.2f * (float)num10);
					}
				}
				if (player.armorEffectDrawShadowLokis)
				{
					for (int num11 = 0; num11 < 3; num11++)
					{
						DrawPlayer(player, Vector2.Lerp(player.shadowPos[num11], player.position + new Vector2(0f, player.gfxOffY), 0.5f), player.shadowRotation[num11], player.shadowOrigin[num11], MathHelper.Lerp(1f, 0.5f + 0.2f * (float)num11, 0.5f));
					}
				}
				if (player.armorEffectDrawShadowSubtle)
				{
					for (int num12 = 0; num12 < 4; num12++)
					{
						position.X = player.position.X + (float)rand.Next(-20, 21) * 0.1f;
						position.Y = player.position.Y + (float)rand.Next(-20, 21) * 0.1f + player.gfxOffY;
						DrawPlayer(player, position, player.fullRotation, player.fullRotationOrigin, 0.9f);
					}
				}
				if (player.shadowDodge)
				{
					player.shadowDodgeCount += 1f;
					if (player.shadowDodgeCount > 30f)
					{
						player.shadowDodgeCount = 30f;
					}
				}
				else
				{
					player.shadowDodgeCount -= 1f;
					if (player.shadowDodgeCount < 0f)
					{
						player.shadowDodgeCount = 0f;
					}
				}
				if (player.shadowDodgeCount > 0f)
				{
					_ = player.position;
					position.X = player.position.X + player.shadowDodgeCount;
					position.Y = player.position.Y + player.gfxOffY;
					DrawPlayer(player, position, player.fullRotation, player.fullRotationOrigin, 0.5f + (float)rand.Next(-10, 11) * 0.005f);
					position.X = player.position.X - player.shadowDodgeCount;
					DrawPlayer(player, position, player.fullRotation, player.fullRotationOrigin, 0.5f + (float)rand.Next(-10, 11) * 0.005f);
				}
				position = player.position;
				position.Y += player.gfxOffY;
				if (player.stoned)
				{
					DrawPlayerStoned(player, position);
				}
				else if (!player.invis)
				{
					DrawPlayer(player, position, player.fullRotation, player.fullRotationOrigin);
				}
				spriteBatch.End();
			}
			TimeLogger.DetailedDrawTime(21);
		}

