			pixelShader.CurrentTechnique.Passes[0].Apply();
			if (!drawPlayer.mount.Active || drawPlayer.mount.Type != 11)
			{
				return;
			}
			for (int num137 = 0; num137 < 1000; num137++)
			{
				if (projectile[num137].active && projectile[num137].owner == drawPlayer.whoAmI && projectile[num137].type == 591)
				{
					instance.DrawProj(num137);
				}
			}
		}

		private void DrawPlayer_DrawAllLayers(Player drawPlayer, int projectileDrawPosition, int cHead)
		{
			int num = -1;
			for (int i = 0; i <= playerDrawData.Count; i++)
			{
				if (projectileDrawPosition == i)
				{
					if (num != 0)
					{
						pixelShader.CurrentTechnique.Passes[0].Apply();
						num = 0;
					}
					projectile[drawPlayer.heldProj].gfxOffY = drawPlayer.gfxOffY;
					try
					{
						DrawProj(drawPlayer.heldProj);
					}
					catch
					{
						projectile[drawPlayer.heldProj].active = false;
					}
				}
				if (i != playerDrawData.Count)
				{
					DrawData value = playerDrawData[i];
					if (!value.sourceRect.HasValue)
					{
						value.sourceRect = value.texture.Frame();
					}
					if (value.shader >= 0)
					{
						GameShaders.Hair.Apply(0, drawPlayer, value);
						GameShaders.Armor.Apply(value.shader, drawPlayer, value);
					}
					else if (drawPlayer.head == 0)
					{
						GameShaders.Hair.Apply(0, drawPlayer, value);
						GameShaders.Armor.Apply(cHead, drawPlayer, value);
					}
					else
					{
						GameShaders.Armor.Apply(0, drawPlayer, value);
						GameShaders.Hair.Apply((short)(-value.shader), drawPlayer, value);
					}
					num = value.shader;
					if (value.texture != null)
					{
						value.Draw(spriteBatch);
					}
				}
			}
		}

