		protected void DrawNPCHouse()
		{
			for (int i = 0; i < 200; i++)
			{
				if (!npc[i].active || !npc[i].townNPC || npc[i].homeless || npc[i].homeTileX <= 0 || npc[i].homeTileY <= 0 || npc[i].type == 37)
				{
					continue;
				}
				int num = 0;
				int homeTileX = npc[i].homeTileX;
				int num2 = npc[i].homeTileY - 1;
				if (WorldGen.TownManager.FindOccupation(homeTileX, num2 + 1) == npc[i].type)
				{
					num = 1;
				}
				if (tile[homeTileX, num2] == null)
				{
					continue;
				}
				bool flag = false;
				while (!tile[homeTileX, num2].active() || !tileSolid[tile[homeTileX, num2].type])
				{
					num2--;
					if (num2 < 10)
					{
						break;
					}
					if (tile[homeTileX, num2] == null)
					{
						flag = true;
						break;
					}
				}
				if (flag)
				{
					continue;
				}
				int num3 = 8;
				int num4 = 18;
				if (tile[homeTileX, num2].type == 19)
				{
					num4 -= 8;
				}
				num2++;
				int num5 = 0;
				float num6 = num2 * 16;
				SpriteEffects effects = SpriteEffects.None;
				Texture2D texture2D = HouseBannerTexture[num];
				if (player[myPlayer].gravDir == -1f)
				{
					num6 -= screenPosition.Y;
					num6 = screenPosition.Y + (float)screenHeight - num6;
					num6 -= (float)texture2D.Height;
					effects = SpriteEffects.FlipVertically;
					num5 = 4;
				}
				spriteBatch.Draw(texture2D, new Vector2(homeTileX * 16 - (int)screenPosition.X + num3, num6 - (float)(int)screenPosition.Y + (float)num4 + (float)num5), new Microsoft.Xna.Framework.Rectangle(0, 0, texture2D.Width, texture2D.Height), Lighting.GetColor(homeTileX, num2), 0f, new Vector2(texture2D.Width / 2, texture2D.Height / 2), 1f, effects, 0f);
				int num7 = NPC.TypeToHeadIndex(npc[i].type);
				float scale = 1f;
				float num8 = 0f;
				num8 = ((npcHeadTexture[num7].Width <= npcHeadTexture[num7].Height) ? ((float)npcHeadTexture[num7].Height) : ((float)npcHeadTexture[num7].Width));
				if (num8 > 24f)
				{
					scale = 24f / num8;
				}
				spriteBatch.Draw(npcHeadTexture[num7], new Vector2(homeTileX * 16 - (int)screenPosition.X + num3, num6 - (float)(int)screenPosition.Y + (float)num4 + 2f), new Microsoft.Xna.Framework.Rectangle(0, 0, npcHeadTexture[num7].Width, npcHeadTexture[num7].Height), Lighting.GetColor(homeTileX, num2), 0f, new Vector2(npcHeadTexture[num7].Width / 2, npcHeadTexture[num7].Height / 2), scale, effects, 0f);
				homeTileX = homeTileX * 16 - (int)screenPosition.X + num3 - texture2D.Width / 2;
				num2 = num2 * 16 - (int)screenPosition.Y + num4 - texture2D.Height / 2;
				if (mouseX >= homeTileX && mouseX <= homeTileX + texture2D.Width && mouseY >= num2 && mouseY <= num2 + texture2D.Height)
				{
					MouseText(npc[i].FullName, 0, 0);
					if (mouseRightRelease && mouseRight)
					{
						mouseRightRelease = false;
						WorldGen.kickOut(i);
						PlaySound(12);
					}
				}
			}
		}

		public void DrawWindowsIMEPanel(Vector2 position, float xAnchor = 0f)
		{
			if (!Platform.Current.Ime.IsCandidateListVisible)
			{
				return;
			}
			List<string> list = new List<string>();
			for (uint num = 0u; num < Platform.Current.Ime.CandidateCount; num++)
			{
				string candidate = Platform.Current.Ime.GetCandidate(num);
				list.Add(candidate);
			}
			if (list.Count == 0)
			{
				return;
			}
			uint selectedCandidate = Platform.Current.Ime.SelectedCandidate;
			DynamicSpriteFont val = fontMouseText;
			float num2 = 0.85f;
			float num3 = 14f;
			float num4 = 0f;
			int num5 = 32;
			num4 += num3;
			string text = "{0,2}: {1}";
			string text2 = "  ";
			for (int i = 0; i < list.Count; i++)
			{
				int num6 = i + 1;
				string text3 = text;
				if (i < list.Count - 1)
				{
					text3 += text2;
				}
				num4 += val.MeasureString(string.Format(text3, num6, list[i])).X * num2;
				num4 += num3;
			}
			Vector2 vector = new Vector2(num4 * (0f - xAnchor), 0f);
			Utils.DrawSettings2Panel(spriteBatch, position + vector + new Vector2(0f, -num5), num4, new Microsoft.Xna.Framework.Color(63, 65, 151, 255) * 0.785f);
			Vector2 pos = position + new Vector2(10f, -num5 / 2) + vector;
			for (uint num7 = 0u; num7 < list.Count; num7++)
			{
				Microsoft.Xna.Framework.Color color = Microsoft.Xna.Framework.Color.Gray;
				if (num7 == selectedCandidate)
				{
					color = Microsoft.Xna.Framework.Color.White;
				}
				uint num8 = num7 + 1;
				string text4 = text;
				if (num7 < list.Count - 1)
				{
					text4 += text2;
				}
				string text5 = string.Format(text4, num8, list[(int)num7]);
				Vector2 vector2 = val.MeasureString(text5) * num2;
				Utils.DrawBorderString(spriteBatch, text5, pos, color, num2, 0f, 0.4f);
				pos.X += vector2.X + num3;
			}
		}

		public void HandleIME()
		{
			if (_imeToggle != PlayerInput.WritingText)
			{
				_imeToggle = PlayerInput.WritingText;
				if (_imeToggle)
				{
					Platform.Current.Ime.Enable();
				}
				else
				{
					Platform.Current.Ime.Disable();
				}
			}
		}

		protected void DrawPlayerChat()
		{
			TextSnippet[] array = null;
			if (drawingPlayerChat)
			{
				PlayerInput.WritingText = true;
			}
			HandleIME();
			if (drawingPlayerChat)
			{
				textBlinkerCount++;
				if (textBlinkerCount >= 20)
				{
					if (textBlinkerState == 0)
					{
						textBlinkerState = 1;
					}
					else
					{
						textBlinkerState = 0;
					}
					textBlinkerCount = 0;
				}
				string text = chatText;
				if (screenWidth > 800)
				{
					int num = screenWidth - 300;
					int num2 = 78;
					spriteBatch.Draw(textBackTexture, new Vector2(num2, screenHeight - 36), new Microsoft.Xna.Framework.Rectangle(0, 0, textBackTexture.Width - 100, textBackTexture.Height), new Microsoft.Xna.Framework.Color(100, 100, 100, 100), 0f, default(Vector2), 1f, SpriteEffects.None, 0f);
					num -= 400;
					num2 += 400;
					while (num > 0)
					{
						if (num > 300)
						{
							spriteBatch.Draw(textBackTexture, new Vector2(num2, screenHeight - 36), new Microsoft.Xna.Framework.Rectangle(100, 0, textBackTexture.Width - 200, textBackTexture.Height), new Microsoft.Xna.Framework.Color(100, 100, 100, 100), 0f, default(Vector2), 1f, SpriteEffects.None, 0f);
							num -= 300;
							num2 += 300;
						}
						else
						{
							spriteBatch.Draw(textBackTexture, new Vector2(num2, screenHeight - 36), new Microsoft.Xna.Framework.Rectangle(textBackTexture.Width - num, 0, textBackTexture.Width - (textBackTexture.Width - num), textBackTexture.Height), new Microsoft.Xna.Framework.Color(100, 100, 100, 100), 0f, default(Vector2), 1f, SpriteEffects.None, 0f);
							num = 0;
						}
					}
				}
				else
				{
					spriteBatch.Draw(textBackTexture, new Vector2(78f, screenHeight - 36), new Microsoft.Xna.Framework.Rectangle(0, 0, textBackTexture.Width, textBackTexture.Height), new Microsoft.Xna.Framework.Color(100, 100, 100, 100), 0f, default(Vector2), 1f, SpriteEffects.None, 0f);
				}
				int hoveredSnippet = -1;
				List<TextSnippet> list = ChatManager.ParseMessage(text, Microsoft.Xna.Framework.Color.White);
				string compositionString = Platform.Current.Ime.CompositionString;
				if (compositionString != null && compositionString.Length > 0)
				{
					list.Add(new TextSnippet(compositionString, new Microsoft.Xna.Framework.Color(255, 240, 20)));
				}
				if (textBlinkerState == 1)
				{
					list.Add(new TextSnippet("|", Microsoft.Xna.Framework.Color.White));
				}
				array = list.ToArray();
				ChatManager.DrawColorCodedStringWithShadow(spriteBatch, fontMouseText, array, new Vector2(88f, screenHeight - 30), 0f, Vector2.Zero, Vector2.One, out hoveredSnippet);
				if (hoveredSnippet > -1)
				{
					array[hoveredSnippet].OnHover();
					if (mouseLeft && mouseLeftRelease)
					{
						array[hoveredSnippet].OnClick();
					}
				}
			}
			int num3 = startChatLine;
			int num4 = startChatLine + showCount;
			if (num4 >= numChatLines)
			{
				num4 = --numChatLines;
				num3 = num4 - showCount;
			}
			int num5 = 0;
			int num6 = -1;
			int num7 = -1;
			for (int i = num3; i < num4; i++)
			{
				if (drawingPlayerChat || (chatLine[i].showTime > 0 && chatLine[i].text.Length > 0))
				{
					int hoveredSnippet2 = -1;
					ChatManager.DrawColorCodedStringWithShadow(spriteBatch, fontMouseText, chatLine[i].parsedText, new Vector2(88f, screenHeight - 30 - 28 - num5 * 21), 0f, Vector2.Zero, Vector2.One, out hoveredSnippet2);
					if (hoveredSnippet2 >= 0 && chatLine[i].parsedText[hoveredSnippet2].CheckForHover)
					{
						num6 = i;
						num7 = hoveredSnippet2;
					}
				}
				num5++;
			}
			if (num6 > -1)
			{
				chatLine[num6].parsedText[num7].OnHover();
				if (mouseLeft && mouseLeftRelease)
				{
					chatLine[num6].parsedText[num7].OnClick();
				}
			}
			if (drawingPlayerChat && array != null)
			{
				Vector2 stringSize = ChatManager.GetStringSize(fontMouseText, array, Vector2.Zero);
				DrawWindowsIMEPanel(new Vector2(88f, screenHeight - 30) + new Vector2(stringSize.X + 10f, -6f));
			}
			TimeLogger.DetailedDrawTime(10);
		}

