		private static int DrawBuffIcon(int drawBuffText, int i, int b, int x, int y)
		{
			if (b == 0)
			{
				return drawBuffText;
			}
			Microsoft.Xna.Framework.Color color = new Microsoft.Xna.Framework.Color(buffAlpha[i], buffAlpha[i], buffAlpha[i], buffAlpha[i]);
			spriteBatch.Draw(buffTexture[b], new Vector2(x, y), new Microsoft.Xna.Framework.Rectangle(0, 0, buffTexture[b].Width, buffTexture[b].Height), color, 0f, default(Vector2), 1f, SpriteEffects.None, 0f);
			if (!vanityPet[b] && !lightPet[b] && !buffNoTimeDisplay[b] && (!player[myPlayer].honeyWet || b != 48) && (!player[myPlayer].wet || !expertMode || b != 46) && player[myPlayer].buffTime[i] > 2)
			{
