				DynamicSpriteFontExtensionMethods.DrawString(spriteBatch, fontItemStack, text, new Vector2(x, y + buffTexture[b].Height), color, 0f, default(Vector2), 0.8f, SpriteEffects.None, 0f);
			}
			if (mouseX < x + buffTexture[b].Width && mouseY < y + buffTexture[b].Height && mouseX > x && mouseY > y)
			{
				drawBuffText = i;
				buffAlpha[i] += 0.1f;
				bool flag = mouseRight && mouseRightRelease;
				if (PlayerInput.UsingGamepad)
				{
					flag = mouseLeft && mouseLeftRelease && playerInventory;
					if (playerInventory)
					{
						player[myPlayer].mouseInterface = true;
					}
				}
				else
				{
					player[myPlayer].mouseInterface = true;
				}
				if (flag)
				{
					TryRemovingBuff(i, b);
				}
			}
			else
			{
				buffAlpha[i] -= 0.05f;
			}
			if (buffAlpha[i] > 1f)
			{
				buffAlpha[i] = 1f;
			}
			else if ((double)buffAlpha[i] < 0.4)
			{
				buffAlpha[i] = 0.4f;
			}
			if (PlayerInput.UsingGamepad && !playerInventory)
			{
				drawBuffText = -1;
			}
			return drawBuffText;
		}

		private static void TryRemovingBuff(int i, int b)
		{
