				if (player[myPlayer].miscEquips[1].buffType == b && !player[myPlayer].hideMisc[1])
				{
					player[myPlayer].hideMisc[1] = true;
				}
				PlaySound(12);
				if (!flag)
				{
					player[myPlayer].DelBuff(i);
				}
			}
		}

