					spriteBatch.Draw(cursorTextures[num], new Vector2(mouseX, mouseY) + vector, sourceRectangle, mouseBorderColor, 0f, origin, scale, SpriteEffects.None, 0f);
				}
				return new Vector2(2f);
			}
			return Vector2.Zero;
		}

		private void OnCharacterNamed(string text)
		{
			PendingPlayer.name = text.Trim();
			PlayerFileData.CreateAndSave(PendingPlayer);
			LoadPlayers();
			menuMode = 1;
		}

		private void OnSeedSelected(string text)
		{
			text = text.Trim();
			if (text.Length == 0)
			{
				ActiveWorldFileData.SetSeedToRandom();
			}
			else
			{
				ActiveWorldFileData.SetSeed(text);
			}
			menuMode = 10;
			WorldGen.CreateNewWorld();
		}

		private void OnWorldNamed(string text)
		{
			menuMode = 10;
			worldName = text.Trim();
			ActiveWorldFileData = WorldFile.CreateMetadata(worldName, SocialAPI.Cloud != null && SocialAPI.Cloud.EnabledByDefault, expertMode);
			if (UseSeedUI)
			{
				menuMode = 5000;
			}
			else
			{
				WorldGen.CreateNewWorld();
