			}
			catch
			{
			}
			tileBatch.End();
			spriteBatch.End();
			base.GraphicsDevice.SetRenderTarget(null);
			base.GraphicsDevice.SetRenderTarget(backgroundTarget);
			base.GraphicsDevice.Clear(Microsoft.Xna.Framework.Color.Transparent);
			spriteBatch.Begin();
			tileBatch.Begin();
			if (ignoreErrors)
			{
				try
				{
					DrawBackground();
				}
				catch (Exception e)
				{
					TimeLogger.DrawException(e);
				}
			}
			else
			{
