			{
				drawWaters(bg: true);
			}
			else
			{
				drawWaters(bg: true, bloodMoon ? 9 : biome.WaterStyle, allowUpdate: false);
			}
			tileBatch.End();
			spriteBatch.End();
			if (captureBackground)
			{
				tileBatch.Begin();
				spriteBatch.Begin();
				DrawBackground();
				tileBatch.End();
				spriteBatch.End();
			}
			tileBatch.Begin();
			spriteBatch.Begin();
			DrawWalls();
			tileBatch.End();
			spriteBatch.End();
