			{
				spriteBatch.Begin();
				DrawWoF();
				spriteBatch.End();
			}
			if (captureEntities)
			{
				spriteBatch.Begin();
				DrawRain();
				spriteBatch.End();
			}
			if (drawBackGore && captureEntities)
			{
				spriteBatch.Begin();
				DrawGoreBehind();
				spriteBatch.End();
				drawBackGore = true;
			}
			if (captureEntities)
			{
				spriteBatch.Begin();
