			}
			else
			{
				DrawTiles(solidOnly: true, biome.WaterStyle);
			}
			tileBatch.End();
			spriteBatch.End();
			tileBatch.Begin();
			spriteBatch.Begin();
			DrawCachedNPCs(DrawCacheNPCsBehindNonSolidTiles, behindTiles: true);
