			{
				DrawTiles(solidOnly: false);
			}
			else
			{
				DrawTiles(solidOnly: false, bloodMoon ? 9 : biome.WaterStyle);
			}
			tileBatch.End();
			spriteBatch.End();
			if (captureEntities)
			{
				spriteBatch.Begin();
				waterfallManager.FindWaterfalls();
				waterfallManager.Draw(spriteBatch);
				spriteBatch.End();
				DrawPlayers();
				DrawCachedProjs(DrawCacheProjsBehindNPCsAndTiles);
				spriteBatch.Begin();
				DrawNPCs(behindTiles: true);
