			tileBatch.Begin();
			spriteBatch.Begin();
			if (biome == null)
			{
				drawWaters();
			}
			else
			{
				drawWaters(bg: false, biome.WaterStyle, allowUpdate: false);
			}
			if (captureMech)
			{
				DrawWires();
			}
			tileBatch.End();
			spriteBatch.End();
