		protected bool checkMap(int i, int j)
		{
			if (mapTarget[i, j] == null || mapTarget[i, j].IsDisposed)
			{
				initMap[i, j] = false;
			}
			if (!initMap[i, j])
			{
				try
				{
					int width = textureMaxWidth;
					int height = textureMaxHeight;
					if (i == mapTargetX - 1)
					{
						width = 400;
					}
					if (j == mapTargetY - 1)
					{
						height = 600;
					}
					mapTarget[i, j] = new RenderTarget2D(base.GraphicsDevice, width, height, mipMap: false, base.GraphicsDevice.PresentationParameters.BackBufferFormat, DepthFormat.Depth16, 0, RenderTargetUsage.PreserveContents);
				}
				catch
				{
					mapEnabled = false;
					for (int k = 0; k < mapTargetX; k++)
					{
						for (int l = 0; l < mapTargetY; l++)
						{
							try
							{
								initMap[k, l] = false;
								mapTarget[k, l].Dispose();
							}
							catch
							{
							}
						}
					}
					return false;
				}
				initMap[i, j] = true;
			}
			return true;
		}

