		protected void DrawSurfaceBG()
		{
			float num = SkyManager.Instance.ProcessCloudAlpha();
			if (!mapFullscreen && (double)screenPosition.Y < worldSurface * 16.0 + 16.0)
			{
				for (int i = 0; i < 200; i++)
				{
					if (cloud[i].active && cloud[i].scale < 1f)
					{
						Microsoft.Xna.Framework.Color color = cloud[i].cloudColor(bgColor);
						float num2 = cloud[i].scale * 0.8f;
						float num3 = (cloud[i].scale + 1f) / 2f * 0.9f;
						color.R = (byte)((float)(int)color.R * num2);
						color.G = (byte)((float)(int)color.G * num3);
						atmo = 1f;
						float num4 = cloud[i].position.Y * ((float)screenHeight / 600f);
						num4 = cloud[i].position.Y + (float)(int)((double)(0f - screenPosition.Y + screenOff / 2f) / (worldSurface * 16.0) * 750.0 + 830.0) + (float)(int)scAdj;
						spriteBatch.Draw(cloudTexture[cloud[i].type], new Vector2(cloud[i].position.X + (float)cloudTexture[cloud[i].type].Width * 0.5f, num4 + (float)cloudTexture[cloud[i].type].Height * 0.5f), new Microsoft.Xna.Framework.Rectangle(0, 0, cloudTexture[cloud[i].type].Width, cloudTexture[cloud[i].type].Height), color * num, cloud[i].rotation, new Vector2((float)cloudTexture[cloud[i].type].Width * 0.5f, (float)cloudTexture[cloud[i].type].Height * 0.5f), cloud[i].scale, cloud[i].spriteDir, 0f);
					}
				}
			}
			if (invasionType == 4 && !SkyManager.Instance["Martian"].IsActive())
			{
				SkyManager.Instance.Activate("Martian", default(Vector2));
			}
			else if (invasionType != 4 && SkyManager.Instance["Martian"].IsActive())
			{
				SkyManager.Instance.Deactivate("Martian");
			}
			SkyManager.Instance.ResetDepthTracker();
			atmo = 1f;
			bgScale *= 2f;
			bgParallax = 0.15;
			if (atmo < 1f)
			{
				backColor.R = (byte)((float)(int)backColor.R * atmo);
				backColor.G = (byte)((float)(int)backColor.G * atmo);
				backColor.B = (byte)((float)(int)backColor.B * atmo);
				backColor.A = (byte)((float)(int)backColor.A * atmo);
			}
			if (!mapFullscreen && (double)(screenPosition.Y / 16f) <= worldSurface + 10.0)
			{
				if (BackgroundEnabled)
				{
					if (cloudBGActive > 0f)
					{
						cloudBGAlpha += 0.0005f * (float)dayRate;
						if (cloudBGAlpha > 1f)
						{
							cloudBGAlpha = 1f;
						}
					}
					else
					{
						cloudBGAlpha -= 0.0005f * (float)dayRate;
						if (cloudBGAlpha < 0f)
						{
							cloudBGAlpha = 0f;
						}
					}
					if (cloudBGAlpha > 0f)
					{
						LoadBackground(cloudBG[0]);
						LoadBackground(cloudBG[1]);
						bgScale *= 2f;
						bgParallax = 0.15;
						float num5 = cloudBGAlpha;
						if (num5 > 1f)
						{
							num5 = 1f;
						}
						bgScale = 1.65f;
						bgParallax = 0.09000000357627869;
						if (base.IsActive)
						{
							cloudBGX[0] += windSpeed * (float)bgParallax * 5f * (float)dayRate;
						}
						if (cloudBGX[0] > (float)backgroundWidth[cloudBG[0]] * bgScale)
						{
							cloudBGX[0] -= (float)backgroundWidth[cloudBG[0]] * bgScale;
						}
						if (cloudBGX[0] < (float)(-backgroundWidth[cloudBG[0]]) * bgScale)
						{
							cloudBGX[0] += (float)backgroundWidth[cloudBG[0]] * bgScale;
						}
						bgW = (int)((float)backgroundWidth[cloudBG[0]] * bgScale);
						bgTop = (int)((double)(0f - screenPosition.Y + screenOff / 2f) / (worldSurface * 16.0) * 900.0 + 600.0) + (int)scAdj;
						if (gameMenu)
						{
							bgTop = -150;
						}
						bgStart = (int)(0.0 - Math.IEEERemainder((double)screenPosition.X * bgParallax, bgW) - (double)(bgW / 2) - (double)bgW);
						bgStart += (int)cloudBGX[0];
						bgLoops = screenWidth / bgW + 2 + 2;
						backColor = trueBackColor;
						backColor.R = (byte)((float)(int)backColor.R * num5);
						backColor.G = (byte)((float)(int)backColor.G * num5);
						backColor.B = (byte)((float)(int)backColor.B * num5);
						backColor.A = (byte)((float)(int)backColor.A * num5);
						SkyManager.Instance.DrawToDepth(spriteBatch, 1f / (float)bgParallax);
						for (int j = 0; j < bgLoops; j++)
						{
							spriteBatch.Draw(backgroundTexture[cloudBG[0]], new Vector2(bgStart + bgW * j, bgTop), new Microsoft.Xna.Framework.Rectangle(0, 0, backgroundWidth[cloudBG[0]], backgroundHeight[cloudBG[0]]), backColor * num, 0f, default(Vector2), bgScale, SpriteEffects.None, 0f);
						}
						num5 = cloudBGAlpha * 1.5f;
						if (num5 > 1f)
						{
							num5 = 1f;
						}
						backColor = trueBackColor;
						backColor.R = (byte)((float)(int)backColor.R * num5);
						backColor.G = (byte)((float)(int)backColor.G * num5);
						backColor.B = (byte)((float)(int)backColor.B * num5);
						backColor.A = (byte)((float)(int)backColor.A * num5);
						bgScale = 1.85f;
						bgParallax = 0.12;
						if (base.IsActive)
						{
							cloudBGX[1] += windSpeed * (float)bgParallax * 5f * (float)dayRate;
						}
						if (cloudBGX[1] > (float)backgroundWidth[cloudBG[1]] * bgScale)
						{
							cloudBGX[1] -= (float)backgroundWidth[cloudBG[1]] * bgScale;
						}
