		private void DrawTileCracks(int crackType)
		{
			Vector2 vector = new Vector2(offScreenRange, offScreenRange);
			if (drawToScreen)
			{
				vector = Vector2.Zero;
			}
			for (int i = 0; i < player[myPlayer].hitTile.data.Length; i++)
			{
				if (player[myPlayer].hitTile.data[i].type != crackType)
				{
					continue;
				}
				int damage = player[myPlayer].hitTile.data[i].damage;
				if (damage < 20)
				{
					continue;
				}
				int x = player[myPlayer].hitTile.data[i].X;
				int y = player[myPlayer].hitTile.data[i].Y;
				if (!WorldGen.InWorld(x, y))
				{
					continue;
				}
				bool flag = tile[x, y] != null;
				if (flag && crackType == 1)
				{
					flag = flag && tile[x, y].active();
				}
				if (flag && crackType == 2)
				{
					flag = flag && tile[x, y].wall != 0;
				}
				if (!flag)
				{
					continue;
				}
				bool flag2 = false;
				bool flag3 = false;
				if (tile[x, y].type == 10)
				{
					flag2 = false;
				}
				else if (tileSolid[tile[x, y].type] && !tileSolidTop[tile[x, y].type])
				{
					flag2 = true;
				}
				else if (tile[x, y].type == 5)
				{
					flag3 = true;
					int num = tile[x, y].frameX / 22;
					int num2 = tile[x, y].frameY / 22;
					if (num2 < 9)
					{
						flag2 = ((num != 1 && num != 2) || num2 < 6 || num2 > 8) && (num != 3 || num2 > 2) && (num != 4 || num2 < 3 || num2 > 5) && ((num != 5 || num2 < 6 || num2 > 8) ? true : false);
					}
				}
				else if (tile[x, y].type == 72)
				{
					flag3 = true;
					if (tile[x, y].frameX <= 34)
					{
						flag2 = true;
					}
				}
				if (flag2 && tile[x, y].slope() == 0 && !tile[x, y].halfBrick())
				{
					int num3 = 0;
					if (damage >= 80)
					{
						num3 = 3;
					}
					else if (damage >= 60)
					{
						num3 = 2;
					}
					else if (damage >= 40)
					{
						num3 = 1;
					}
					else if (damage >= 20)
					{
						num3 = 0;
					}
					Microsoft.Xna.Framework.Rectangle value = new Microsoft.Xna.Framework.Rectangle(player[myPlayer].hitTile.data[i].crackStyle * 18, num3 * 18, 16, 16);
					if (flag3)
					{
						value.X = (4 + player[myPlayer].hitTile.data[i].crackStyle / 2) * 18;
					}
					spriteBatch.Draw(tileCrackTexture, new Vector2(x * 16 - (int)screenPosition.X, y * 16 - (int)screenPosition.Y) + vector, value, Lighting.GetColor(x, y), 0f, default(Vector2), 1f, SpriteEffects.None, 0f);
				}
			}
		}

		private static void CheckMonoliths()
		{
			bool flag = player[myPlayer].ZoneTowerVortex || player[myPlayer].ZoneTowerNebula || player[myPlayer].ZoneTowerStardust || player[myPlayer].ZoneTowerSolar;
			for (int i = 0; i < MonolithFilterNames.Length; i++)
			{
				if (!flag && i == monolithType)
				{
					if (!Filters.Scene[MonolithFilterNames[monolithType]].IsActive())
					{
						Filters.Scene.Activate(MonolithFilterNames[monolithType], default(Vector2));
					}
					if (!SkyManager.Instance[MonolithSkyNames[i]].IsActive())
					{
						SkyManager.Instance.Activate(MonolithSkyNames[i], default(Vector2));
					}
				}
				else
				{
					if (Filters.Scene[MonolithFilterNames[i]].IsActive())
					{
						Filters.Scene.Deactivate(MonolithFilterNames[i]);
					}
					if (SkyManager.Instance[MonolithSkyNames[i]].IsActive())
					{
						SkyManager.Instance.Deactivate(MonolithSkyNames[i]);
					}
				}
			}
		}

