		public void DrawInfernoRings()
		{
			for (int i = 0; i < 255; i++)
			{
				if (!player[i].active || player[i].outOfRange || !player[i].inferno || player[i].dead)
				{
					continue;
				}
				LoadFlameRing();
				float num = 1f;
				float num2 = 0.1f;
				float num3 = 0.9f;
				if (!gamePaused && base.IsActive)
				{
					player[i].flameRingScale += 0.004f;
				}
				if (player[i].flameRingScale < 1f)
				{
					num = player[i].flameRingScale;
				}
				else
				{
					player[i].flameRingScale = 0.8f;
					num = player[i].flameRingScale;
				}
				if (!gamePaused && base.IsActive)
				{
					player[i].flameRingRot += 0.05f;
				}
				if (player[i].flameRingRot > (float)Math.PI * 2f)
				{
					player[i].flameRingRot -= (float)Math.PI * 2f;
				}
				if (player[i].flameRingRot < (float)Math.PI * -2f)
				{
					player[i].flameRingRot += (float)Math.PI * 2f;
				}
				for (int j = 0; j < 3; j++)
				{
					float num4 = num + num2 * (float)j;
					if (num4 > 1f)
					{
						num4 -= num2 * 2f;
					}
					float num5 = MathHelper.Lerp(0.8f, 0f, Math.Abs(num4 - num3) * 10f);
					spriteBatch.Draw(flameRingTexture, player[i].Center - screenPosition, new Microsoft.Xna.Framework.Rectangle(0, 400 * j, 400, 400), new Microsoft.Xna.Framework.Color(num5, num5, num5, num5 / 2f), player[i].flameRingRot + (float)Math.PI / 3f * (float)j, new Vector2(200f, 200f), num4, SpriteEffects.None, 0f);
				}
			}
		}

		private static void UpdateInvasion()
		{
			if (invasionType <= 0)
			{
				return;
			}
			if (invasionSize <= 0)
			{
				if (invasionType == 1)
				{
					NPC.downedGoblins = true;
					if (netMode == 2)
					{
						NetMessage.SendData(7);
					}
					AchievementsHelper.NotifyProgressionEvent(10);
				}
				else if (invasionType == 2)
				{
					NPC.downedFrost = true;
					AchievementsHelper.NotifyProgressionEvent(12);
				}
				else if (invasionType == 3)
				{
					NPC.downedPirates = true;
					AchievementsHelper.NotifyProgressionEvent(11);
				}
				else if (invasionType == 4)
				{
					NPC.downedMartians = true;
					AchievementsHelper.NotifyProgressionEvent(13);
				}
				InvasionWarning();
				invasionType = 0;
				invasionDelay = 0;
			}
			if (invasionX == (double)spawnTileX)
			{
				return;
			}
			float num = dayRate;
			if (invasionX > (double)spawnTileX)
			{
				invasionX -= num;
				if (invasionX <= (double)spawnTileX)
				{
					invasionX = spawnTileX;
					InvasionWarning();
				}
				else
				{
					invasionWarn--;
				}
			}
			else if (invasionX < (double)spawnTileX)
			{
				invasionX += num;
				if (invasionX >= (double)spawnTileX)
				{
					invasionX = spawnTileX;
					InvasionWarning();
				}
				else
				{
					invasionWarn--;
				}
			}
			if (invasionWarn <= 0)
			{
				invasionWarn = 3600;
				InvasionWarning();
			}
		}

		private static void InvasionWarning()
		{
			LocalizedText empty = LocalizedText.Empty;
			empty = ((invasionSize <= 0) ? ((invasionType == 2) ? Lang.misc[4] : ((invasionType == 3) ? Lang.misc[24] : ((invasionType != 4) ? (empty = Lang.misc[0]) : Lang.misc[42]))) : ((invasionX < (double)spawnTileX) ? ((invasionType == 2) ? Lang.misc[5] : ((invasionType == 3) ? Lang.misc[25] : ((invasionType != 4) ? (empty = Lang.misc[1]) : LocalizedText.Empty))) : ((invasionX > (double)spawnTileX) ? ((invasionType == 2) ? Lang.misc[6] : ((invasionType == 3) ? Lang.misc[26] : ((invasionType != 4) ? (empty = Lang.misc[2]) : LocalizedText.Empty))) : ((invasionType == 2) ? Lang.misc[7] : ((invasionType == 3) ? Lang.misc[27] : ((invasionType != 4) ? (empty = Lang.misc[3]) : Lang.misc[41]))))));
			if (netMode == 0)
			{
				NewText(empty.ToString(), 175, 75);
			}
			else if (netMode == 2 && empty.Value != "")
			{
				NetMessage.BroadcastChatMessage(NetworkText.FromKey(empty.Key), new Microsoft.Xna.Framework.Color(175, 75, 255));
			}
		}

		public static bool CanStartInvasion(int type = 1, bool ignoreDelay = false)
		{
			if (invasionType != 0)
			{
				return false;
			}
			if (invasionDelay != 0 && !ignoreDelay)
			{
				return false;
			}
			int num = 0;
			for (int i = 0; i < 255; i++)
			{
				if (player[i].active && player[i].statLifeMax >= 200)
				{
					num++;
				}
			}
			return num > 0;
		}

		public static void StartInvasion(int type = 1)
		{
			if (invasionType != 0 && invasionSize == 0)
			{
				invasionType = 0;
			}
			if (invasionType != 0)
			{
				return;
			}
			int num = 0;
			for (int i = 0; i < 255; i++)
			{
				if (player[i].active && player[i].statLifeMax >= 200)
				{
					num++;
				}
			}
			if (num > 0)
			{
				invasionType = type;
				invasionSize = 80 + 40 * num;
				if (type == 3)
				{
					invasionSize += 40 + 20 * num;
				}
				if (type == 4)
				{
					invasionSize = 160 + 40 * num;
				}
				invasionSizeStart = invasionSize;
				invasionProgress = 0;
				invasionProgressIcon = type + 3;
				invasionProgressWave = 0;
				invasionProgressMax = invasionSizeStart;
				invasionWarn = 0;
				if (type == 4)
				{
					invasionX = spawnTileX - 1;
					invasionWarn = 2;
				}
				else if (rand.Next(2) == 0)
				{
					invasionX = 0.0;
				}
				else
				{
					invasionX = maxTilesX;
				}
			}
		}

		public static void FakeLoadInvasionStart()
		{
			int num = 0;
			int num2 = 0;
			switch (invasionType)
			{
			case 1:
			case 2:
				num = 80;
				num2 = 40;
				break;
			case 3:
				num = 120;
				num2 = 60;
				break;
			case 4:
				num = 160;
				num2 = 40;
				break;
			}
			int num3 = (int)Math.Ceiling((float)(invasionSize - num) / (float)num2);
			invasionSizeStart = num;
			if (num3 > 0)
			{
				invasionSizeStart += num3 * num2;
			}
		}

		private static void UpdateClient()
		{
			if (myPlayer == 255)
			{
				Netplay.disconnect = true;
			}
			netPlayCounter++;
			if (netPlayCounter > 3600)
			{
				netPlayCounter = 0;
			}
			if (netPlayCounter % 420 == 0)
			{
				NetMessage.SendData(13, -1, -1, null, myPlayer);
			}
			if (netPlayCounter % 900 == 0)
			{
				NetMessage.SendData(36, -1, -1, null, myPlayer);
				NetMessage.SendData(16, -1, -1, null, myPlayer);
				NetMessage.SendData(40, -1, -1, null, myPlayer);
			}
			if (Netplay.Connection.IsActive)
			{
				Netplay.Connection.TimeOutTimer++;
				if (!stopTimeOuts && Netplay.Connection.TimeOutTimer > 7200)
				{
					statusText = Lang.inter[43].Value;
					Netplay.disconnect = true;
				}
			}
			for (int i = 0; i < 400; i++)
			{
				if (item[i].active && item[i].owner == myPlayer)
				{
					item[i].FindOwner(i);
				}
			}
		}

		private static void UpdateServer()
		{
			netPlayCounter++;
			if (netPlayCounter % 3600 == 0)
			{
				NetMessage.SendData(7);
				netPlayCounter = 0;
			}
			for (int i = 0; i < maxNetPlayers; i++)
			{
				if (player[i].active && Netplay.Clients[i].IsActive)
				{
					Netplay.Clients[i].SpamUpdate();
				}
			}
			if (Math.IEEERemainder(netPlayCounter, 900.0) == 0.0)
			{
				bool flag = true;
				int num = lastItemUpdate;
				int num2 = 0;
				while (flag)
				{
					num++;
					if (num >= 400)
					{
						num = 0;
					}
					num2++;
					if (!item[num].active || item[num].owner == 255)
					{
						NetMessage.SendData(21, -1, -1, null, num);
					}
					if (num2 >= maxItemUpdates || num == lastItemUpdate)
					{
						flag = false;
					}
				}
				lastItemUpdate = num;
			}
			for (int j = 0; j < 400; j++)
			{
				if (item[j].active && (item[j].owner == 255 || !player[item[j].owner].active))
				{
					item[j].FindOwner(j);
				}
			}
			for (int k = 0; k < 255; k++)
			{
				if (Netplay.Clients[k].IsActive)
				{
					Netplay.Clients[k].TimeOutTimer++;
					if (!stopTimeOuts && Netplay.Clients[k].TimeOutTimer > 7200)
					{
						Netplay.Clients[k].PendingTermination = true;
					}
				}
				if (player[k].active)
				{
					RemoteClient.CheckSection(k, player[k].position);
				}
			}
		}

		public static void NewText(string newText, byte R = byte.MaxValue, byte G = byte.MaxValue, byte B = byte.MaxValue, bool force = false)
		{
			int num = 80;
			if (!force && newText.Length > num)
			{
				string text = newText;
				while (text.Length > num)
				{
					int num2 = num;
					int num3 = num2;
					while (text.Substring(num3, 1) != " ")
					{
						num3--;
						if (num3 < 1)
						{
							break;
						}
					}
					if (num3 == 0)
					{
						while (text.Substring(num2, 1) != " ")
						{
							num2++;
							if (num2 >= text.Length - 1)
							{
								break;
							}
						}
					}
					else
					{
						num2 = num3;
					}
					if (num2 >= text.Length - 1)
					{
						num2 = text.Length;
					}
					NewText(text.Substring(0, num2), R, G, B, force: true);
					text = text.Substring(num2);
					if (text.Length > 0)
					{
						while (text.Substring(0, 1) == " ")
						{
							text = text.Substring(1);
						}
					}
				}
				if (text.Length > 0)
				{
					NewText(text, R, G, B, force: true);
				}
			}
			else
			{
				for (int num4 = numChatLines - 1; num4 > 0; num4--)
				{
					chatLine[num4].text = chatLine[num4 - 1].text;
					chatLine[num4].parsedText = chatLine[num4 - 1].parsedText;
					chatLine[num4].showTime = chatLine[num4 - 1].showTime;
					chatLine[num4].color = chatLine[num4 - 1].color;
				}
				if (R == 0 && G == 0 && B == 0)
				{
					chatLine[0].color = Microsoft.Xna.Framework.Color.White;
				}
				else
				{
					chatLine[0].color = new Microsoft.Xna.Framework.Color(R, G, B);
				}
				chatLine[0].text = newText;
				chatLine[0].parsedText = ChatManager.ParseMessage(chatLine[0].text, chatLine[0].color).ToArray();
				chatLine[0].showTime = chatLength;
				PlaySound(12);
			}
		}

		public static void NewTextMultiline(string text, bool force = false, Microsoft.Xna.Framework.Color c = default(Microsoft.Xna.Framework.Color), int WidthLimit = -1)
		{
			if (c == default(Microsoft.Xna.Framework.Color))
			{
				c = Microsoft.Xna.Framework.Color.White;
			}
			List<List<TextSnippet>> list = ((WidthLimit == -1) ? Utils.WordwrapStringSmart(text, c, fontMouseText, TextMaxLengthForScreen, 10) : Utils.WordwrapStringSmart(text, c, fontMouseText, WidthLimit, 10));
			for (int i = 0; i < list.Count; i++)
			{
				NewText(list[i]);
			}
		}

		public static void NewText(List<TextSnippet> snippets)
		{
			for (int num = numChatLines - 1; num > 0; num--)
			{
				chatLine[num].text = chatLine[num - 1].text;
				chatLine[num].parsedText = chatLine[num - 1].parsedText;
				chatLine[num].showTime = chatLine[num - 1].showTime;
				chatLine[num].color = chatLine[num - 1].color;
			}
			chatLine[0].text = "whatever";
			chatLine[0].parsedText = snippets.ToArray();
			chatLine[0].showTime = chatLength;
			PlaySound(12);
		}

		public static void NewTextMultilineOld(string text, bool force = false, Microsoft.Xna.Framework.Color c = default(Microsoft.Xna.Framework.Color))
		{
			if (c == default(Microsoft.Xna.Framework.Color))
			{
				c = Microsoft.Xna.Framework.Color.White;
			}
			int lineAmount;
			string[] array = Utils.WordwrapString(text, fontMouseText, 460, 10, out lineAmount);
			for (int i = 0; i <= lineAmount; i++)
			{
				NewText(array[i], c.R, c.G, c.B, force);
			}
		}

		private static void StopRain()
		{
			rainTime = 0;
			raining = false;
			maxRaining = 0f;
		}

		private static void StartRain()
		{
			int num = 86400;
			int num2 = num / 24;
			rainTime = rand.Next(num2 * 8, num);
			if (rand.Next(3) == 0)
			{
				rainTime += rand.Next(0, num2);
			}
			if (rand.Next(4) == 0)
			{
				rainTime += rand.Next(0, num2 * 2);
			}
			if (rand.Next(5) == 0)
			{
				rainTime += rand.Next(0, num2 * 2);
			}
			if (rand.Next(6) == 0)
			{
				rainTime += rand.Next(0, num2 * 3);
			}
			if (rand.Next(7) == 0)
			{
				rainTime += rand.Next(0, num2 * 4);
			}
			if (rand.Next(8) == 0)
			{
				rainTime += rand.Next(0, num2 * 5);
			}
			float num3 = 1f;
			if (rand.Next(2) == 0)
			{
				num3 += 0.05f;
			}
			if (rand.Next(3) == 0)
			{
				num3 += 0.1f;
			}
			if (rand.Next(4) == 0)
			{
				num3 += 0.15f;
			}
			if (rand.Next(5) == 0)
			{
				num3 += 0.2f;
			}
			rainTime = (int)((float)rainTime * num3);
			ChangeRain();
			raining = true;
		}

		private static void ChangeRain()
		{
			if (cloudBGActive >= 1f || (double)numClouds > 150.0)
			{
				if (rand.Next(3) == 0)
				{
					maxRaining = (float)rand.Next(20, 90) * 0.01f;
				}
				else
				{
					maxRaining = (float)rand.Next(40, 90) * 0.01f;
				}
			}
			else if ((double)numClouds > 100.0)
			{
				if (rand.Next(3) == 0)
				{
					maxRaining = (float)rand.Next(10, 70) * 0.01f;
				}
				else
				{
					maxRaining = (float)rand.Next(20, 60) * 0.01f;
				}
			}
			else if (rand.Next(3) == 0)
			{
				maxRaining = (float)rand.Next(5, 40) * 0.01f;
			}
			else
			{
				maxRaining = (float)rand.Next(5, 30) * 0.01f;
			}
		}

		public static void StartSlimeRain(bool announce = true)
		{
			if (slimeRain)
			{
				return;
			}
			if (netMode == 1)
			{
				slimeRainTime = 54000.0;
				slimeRain = true;
				SkyManager.Instance.Activate("Slime", default(Vector2));
			}
			else
			{
				if (raining)
				{
					return;
				}
				slimeRainTime = rand.Next(32400, 54000);
				slimeRain = true;
				slimeRainKillCount = 0;
				if (netMode == 0)
				{
					SkyManager.Instance.Activate("Slime", default(Vector2));
					if (announce)
					{
						slimeWarningTime = slimeWarningDelay;
					}
				}
				else if (announce)
				{
					slimeWarningTime = slimeWarningDelay;
					NetMessage.SendData(7);
				}
			}
		}

		public static void StopSlimeRain(bool announce = true)
		{
			if (!slimeRain)
			{
				return;
			}
			if (netMode == 1)
			{
				slimeRainTime = 0.0;
				slimeRain = false;
				SkyManager.Instance.Deactivate("Slime");
				return;
			}
			int num = 86400 * 7;
			if (hardMode)
			{
				num *= 2;
			}
			slimeRainTime = -rand.Next(3024, 6048) * 100;
			slimeRain = false;
			if (netMode == 0)
			{
				if (announce)
				{
					slimeWarningTime = slimeWarningDelay;
				}
				SkyManager.Instance.Deactivate("Slime");
			}
			else if (announce)
			{
				slimeWarningTime = slimeWarningDelay;
				NetMessage.SendData(7);
			}
		}

		private static void UpdateTime()
		{
			if (pumpkinMoon)
			{
				bloodMoon = false;
				snowMoon = false;
			}
			if (snowMoon)
			{
				bloodMoon = false;
			}
			if ((netMode != 1 && !gameMenu) || netMode == 2)
			{
				if (slimeRainTime > 0.0)
				{
					slimeRainTime -= dayRate;
					if (slimeRainTime <= 0.0)
					{
						StopSlimeRain();
					}
				}
				else if (slimeRainTime < 0.0)
				{
					slimeRainTime += dayRate;
					if (slimeRainTime > 0.0)
					{
						slimeRainTime = 0.0;
					}
				}
				if (raining)
				{
					rainTime -= dayRate;
					if (dayRate > 0)
					{
						int num = 86400 / dayRate / 24;
						if (rainTime <= 0)
						{
							StopRain();
						}
						else if (rand.Next(num * 2) == 0)
						{
							ChangeRain();
						}
					}
				}
				else if (!slimeRain)
				{
					int num2 = 86400;
					num2 /= ((dayRate == 0) ? 1 : dayRate);
					if (rand.Next((int)((double)num2 * 5.5)) == 0)
					{
						StartRain();
					}
					else if (cloudBGActive >= 1f && rand.Next(num2 * 4) == 0)
					{
						StartRain();
					}
					if (!raining && !NPC.BusyWithAnyInvasionOfSorts())
					{
						int num3 = (int)(1728000.0 / (double)dayRate);
						if (!NPC.downedSlimeKing)
						{
							num3 /= 2;
						}
						if (hardMode)
						{
							num3 = (int)((double)num3 * 1.5);
						}
						bool flag = false;
						for (int i = 0; i < 255; i++)
						{
							if (player[i].active && player[i].statLifeMax > 140 && player[i].statDefense > 8)
							{
								flag = true;
							}
						}
						if (!flag)
						{
							num3 *= 5;
						}
						if (dayRate > 0 && num3 > 0 && (flag || expertMode) && rand.Next(num3) == 0)
						{
							StartSlimeRain();
						}
					}
				}
			}
			if (maxRaining != oldMaxRaining)
			{
				if (netMode == 2)
				{
					NetMessage.SendData(7);
				}
				oldMaxRaining = maxRaining;
			}
			UpdateSundial();
			time += dayRate;
			CultistRitual.UpdateTime();
			BirthdayParty.UpdateTime();
			Sandstorm.UpdateTime();
			DD2Event.UpdateTime();
			if (NPC.MoonLordCountdown > 0)
			{
				float num4 = MathHelper.Clamp((float)Math.Sin((float)NPC.MoonLordCountdown / 60f * 0.5f) * 2f, 0f, 1f);
				num4 *= 0.75f - 0.5f * ((float)NPC.MoonLordCountdown / 3600f);
				if (!Filters.Scene["MoonLordShake"].IsActive())
				{
					Filters.Scene.Activate("MoonLordShake", player[myPlayer].position);
				}
				Filters.Scene["MoonLordShake"].GetShader().UseIntensity(num4);
			}
			else if (Filters.Scene["MoonLordShake"].IsActive())
			{
				Filters.Scene.Deactivate("MoonLordShake");
			}
			if (NPC.MoonLordCountdown > 0)
			{
				NPC.MoonLordCountdown--;
				if (NPC.MoonLordCountdown <= 0 && netMode != 1)
				{
					NPC.SpawnOnPlayer(Player.FindClosest(new Vector2(maxTilesX / 2, (float)worldSurface / 2f) * 16f, 0, 0), 398);
				}
			}
			if (NPC.taxCollector && netMode != 2 && !gameMenu)
			{
				player[myPlayer].taxTimer += dayRate;
				if (player[myPlayer].taxTimer >= Player.taxRate)
				{
					player[myPlayer].taxTimer -= Player.taxRate;
					player[myPlayer].CollectTaxes();
				}
			}
			if (netMode != 1 && slimeWarningTime > 0)
			{
				slimeWarningTime--;
				if (slimeWarningTime <= 0)
				{
					if (netMode == 0)
					{
						if (slimeRainTime > 0.0)
						{
							NewText(Lang.gen[74].Value, 50, byte.MaxValue, 130);
						}
						else
						{
							NewText(Lang.gen[75].Value, 50, byte.MaxValue, 130);
						}
					}
					else if (slimeRainTime > 0.0)
					{
						NetMessage.BroadcastChatMessage(NetworkText.FromKey(Lang.gen[74].Key), new Microsoft.Xna.Framework.Color(50, 255, 130));
					}
					else
					{
